  cookie: { maxAge: 24*60*60*1000 }
});

// Customer sessions (separate)
const customerSessionMiddleware = session({
  store: new FileStore({ dir: './customer_sessions' }),
  name: 'customer_session',  // Different cookie name
  secret: 'customer_secret_key',
  resave: false,
  saveUninitialized: false,
  cookie: { maxAge: 24*60*60*1000 }
});
```

## 2. **Authentication Middleware**

```javascript
const authUser = (req, res, next) => {
  if (!req.session.userId) return res.status(401).send('Unauthorized');
  next();
};

const authCustomer = (req, res, next) => {
  if (!req.session.customerId) return res.status(401).send('Unauthorized');
  next();
};
```

