def provide_user_service(common_service: CommonService) -> UserService:
    return UserService(common_service)

class UserController(Controller):
    path = "/users"

    @get()
    def get_user(self, user_service: UserService) -> dict:
        return user_service.get_user()

app = Litestar(
    route_handlers=[UserController],
    dependencies={"common_service": Provide(provide_common_service), "user_service": Provide(provide_user_service)}
)
```

